/* Test driver */
public class Main {
    public static void main(String[] args) {
        Playlist p = new Playlist("PL");
        p.addSong(new Song("1","A","X","Al",10));
        p.addSong(new Song("2","B","X","Al",10));
        MusicPlayer mp = new MusicPlayer();
        mp.loadPlaylist(p);
        mp.addToQueue(new Song("9","Z","Q","Q",1));
        Song s = mp.next();
        if (s != null && s.getTitle().equals("Z")) System.out.println("QUEUE_OK");
        else System.out.println("QUEUE_FAIL");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        Playlist p = new Playlist("PL");
        p.addSong(new Song("1","A","X","Al",10));
        MusicPlayer mp = new MusicPlayer();
        mp.loadPlaylist(p);
        mp.play();
        mp.pause();
        if (mp.getState().getStateName().equals("PAUSED")) System.out.println("PAUSED_OK");
        else System.out.println("PAUSED_FAIL");
    }
}
